      11'd1769: r = 16'd58;
      11'd1770: r = 16'd116;
      11'd1771: r = 16'd29;
      11'd1772: r = 16'd29;
      11'd1773: r = 16'd58;
      11'd1774: r = 16'd29;
      11'd1775: r = 16'd29;
      11'd1776: r = 16'd58;
      11'd1777: r = 16'd116;
      11'd1778: r = 16'd232;
      11'd1779: r = 16'd435;
      11'd1780: r = 16'd870;
      11'd1781: r = 16'd1740;
      11'd1782: r = 16'd3480;
      11'd1783: r = 16'd6960;
      11'd1784: r = 16'd13050;
      default: r='0; endcase f_clo=r; endfunction
  function automatic logic [15:0] lstep(input logic [15:0] s);
    lstep=(s>>1)^(s[0]?TAPS:16'h0); endfunction
  typedef enum logic [1:0] {IDLE,WALK,EMIT} st_e; st_e st;
  logic [15:0] lfsr,R; logic [10:0] idx; logic [4:0] lvl; logic [14:0] acc;
  logic [15:0] clo_c; logic bitc; assign clo_c=f_clo(idx); assign bitc=(R>=clo_c);
  always_ff @(posedge clk or negedge rst_n) if(!rst_n) begin
      st<=IDLE; lfsr<=SEED; valid<=0; sample_o<='0; idx<='0; R<='0; lvl<='0; acc<='0;
    end else begin valid<=0; case(st)
      IDLE: if(req) begin R<=lfsr%NSOL; idx<=ROOT; lvl<='0; acc<='0; st<=WALK; end
      WALK: begin acc[lvl[3:0]]<=bitc; idx<=bitc?f_hi(idx):f_lo(idx);
                  R<=bitc?(R-clo_c):R; lvl<=lvl+5'd1;
                  if(lvl==5'd14) st<=EMIT; end
      EMIT: begin sample_o<=acc; valid<=1; lfsr<=lstep(lfsr); st<=IDLE; end
      default: st<=IDLE; endcase end
endmodule
